const fs = require("fs");
const axios = require("axios");

// read transcript
const transcript = fs.readFileSync(
  "/dataset/demo_calls/transcript.txt",
  "utf8"
);

// strict prompt
const prompt = `
You are a strict data extraction system.

Extract business configuration from this transcript.

Return ONLY valid JSON.

Rules:
- Output must start with { and end with }
- Do not include explanations
- Do not include markdown
- If information is missing return null
- Never assume missing information

JSON schema:

{
 "account_id": "transcript",
 "company_name": null,
 "business_hours": null,
 "office_address": null,
 "services_supported": [],
 "emergency_definition": [],
 "emergency_routing_rules": null,
 "non_emergency_routing_rules": null,
 "call_transfer_rules": null,
 "integration_constraints": [],
 "after_hours_flow_summary": null,
 "office_hours_flow_summary": null,
 "questions_or_unknowns": [],
 "notes": null
}

Transcript:
${transcript}
`;

// call ollama
const response = await axios.post(
  "http://host.docker.internal:11434/api/generate",
  {
    model: "llama3",
    prompt: prompt,
    stream: false
  }
);

return [
  {
    json: {
      raw_output: response.data.response
    }
  }
];

const fs = require("fs");

// read memo
const memoPath = items[0].json.memo_saved;

const memo = JSON.parse(
  fs.readFileSync(memoPath, "utf8")
);

const accountId = memo.account_id || "transcript";

const agent = {

  version: "v1",

  agent_name: `${memo.company_name || "Service"} AI Assistant`,

  voice_style: "calm professional",

  variables: {

    timezone: memo.business_hours?.timezone || null,

    business_hours: memo.business_hours || null,

    office_address: memo.office_address || null

  },

  system_prompt: `
You are Clara, an AI call assistant for ${memo.company_name || "a service company"}.

You handle inbound service calls and route them appropriately.

Do NOT mention internal systems or tools.

BUSINESS HOURS FLOW:

1. Greet caller
2. Ask how you can help
3. Collect caller name
4. Collect caller phone number
5. Determine request type
6. Transfer to dispatcher if needed
7. If transfer fails apologize and promise callback
8. Ask if anything else is needed
9. Close the call politely

AFTER HOURS FLOW:

1. Greet caller
2. Ask purpose of call
3. Determine if emergency
4. If emergency collect:
   - name
   - phone number
   - service address
5. Attempt transfer to on-call technician
6. If transfer fails apologize and confirm quick follow-up
7. If non-emergency collect details for next business day
8. Ask if anything else is needed
9. Close the call
`,

  call_transfer_protocol: {

    timeout_seconds: 60,

    retries: 2

  },

  fallback_protocol: "If transfer fails after retries, apologize and confirm dispatch will return the call shortly."

};

// output directory
const outDir = `/outputs/accounts/${accountId}/v1`;

// save agent spec
fs.writeFileSync(
  `${outDir}/agent_spec.json`,
  JSON.stringify(agent, null, 2)
);

return [
  {
    json: {
      agent_spec_saved: `${outDir}/agent_spec.json`
    }
  }
];

const fs = require("fs");

const memo = items[0].json;

const accountId = memo.account_id || "transcript";

const outputDir = `/outputs/accounts/${accountId}/v1`;

fs.mkdirSync(outputDir, { recursive: true });

fs.writeFileSync(
  `${outputDir}/memo.json`,
  JSON.stringify(memo, null, 2)
);

return [
  {
    json: {
      memo_saved: `${outputDir}/memo.json`,
      account_id: accountId
    }
  }
];

let raw = items[0].json.raw_output;

// clean markdown if model added it
raw = raw.replace(/```json/g, "")
         .replace(/```/g, "")
         .trim();

// extract JSON block
const match = raw.match(/\{[\s\S]*\}/);

let memo;

if (match) {
  try {
    memo = JSON.parse(match[0]);
  } catch (err) {
    memo = {
      error: "Invalid JSON from LLM",
      raw_output: raw
    };
  }
} else {
  memo = {
    error: "No JSON detected",
    raw_output: raw
  };
}

// enforce schema
memo.services_supported = memo.services_supported || [];
memo.emergency_definition = memo.emergency_definition || [];
memo.integration_constraints = memo.integration_constraints || [];
memo.questions_or_unknowns = memo.questions_or_unknowns || [];

// detect missing fields
if (!memo.company_name) {
  memo.questions_or_unknowns.push("company_name missing from transcript");
}

if (!memo.business_hours) {
  memo.questions_or_unknowns.push("business_hours not specified");
}

if (!memo.office_address) {
  memo.questions_or_unknowns.push("office_address not mentioned");
}

return [
  {
    json: memo
  }
];
